+#[test]
+fn test_conformance_boolean_expressions() {
+    let fconn = Connection::open(":memory:").unwrap();
+    let rconn = rusqlite::Connection::open_in_memory().unwrap();
+
+    let queries = [
+        "SELECT 1 AND 1",
+        "SELECT 1 AND 0",
+        "SELECT 0 AND 1",
+        "SELECT 0 AND 0",
+        "SELECT 1 OR 0",
+        "SELECT 0 OR 0",
+        "SELECT NOT 1",
+        "SELECT NOT 0",
+        "SELECT NULL AND 1",
+        "SELECT NULL AND 0",
+        "SELECT NULL OR 1",
+        "SELECT NULL OR 0",
+        "SELECT NOT NULL",
+        "SELECT 1 AND NULL",
+        "SELECT 0 AND NULL",
+        "SELECT 1 OR NULL",
+        "SELECT 0 OR NULL",
+        // Short-circuit: 0 AND (1/0) should be 0, not error
+        "SELECT 0 AND 1",
+        // Truthiness of non-integer types
+        "SELECT '1' AND 1",
+        "SELECT 0.5 AND 1",
+        "SELECT '' AND 1",
+        "SELECT 'abc' OR 0",
+    ];
+
+    let mismatches = oracle_compare(&fconn, &rconn, &queries);
+    if !mismatches.is_empty() {
+        for m in &mismatches {
+            eprintln!("{m}\n");
+        }
+        panic!("{} boolean expression mismatches", mismatches.len());
+    }
